// OPC-UAから受信したデータをCSV用に整形
const payload = msg.payload;

// タイムスタンプ
const ts = payload.sourceTimestamp
  ? new Date(payload.sourceTimestamp).toISOString()
  : new Date().toISOString();

// ノードID
const nodeId = msg.topic || payload.nodeId || 'unknown';

// 値
const value = payload.value !== undefined ? payload.value : payload;

// データ型
const dataType = payload.dataType || typeof value;

// ステータス
const status = payload.statusCode
  ? (payload.statusCode.name || payload.statusCode.toString())
  : 'Good';

// CSVの1行データとして格納
msg.csvRow = { ts, nodeId, value, dataType, status };
return msg;

// バッファ設定
const BUFFER_SIZE = 100;  // ← 件数でフラッシュする閾値
const FLUSH_INTERVAL_MS = 30000;  // ← 時間でフラッシュする間隔(ms)

// コンテキストからバッファを取得
const buffer = context.get('buffer') || [];
const lastFlush = context.get('lastFlush') || Date.now();

if (msg.flush) {
  // 手動フラッシュ
  if (buffer.length === 0) return null;
  context.set('buffer', []);
  context.set('lastFlush', Date.now());
  msg.csvRows = buffer;
  return msg;
}

if (msg.csvRow) {
  buffer.push(msg.csvRow);
  context.set('buffer', buffer);
}

// フラッシュ条件チェック
const now = Date.now();
const timeExceeded = (now - lastFlush) >= FLUSH_INTERVAL_MS;
const sizeExceeded = buffer.length >= BUFFER_SIZE;

if (sizeExceeded || timeExceeded) {
  if (buffer.length === 0) return null;
  context.set('buffer', []);
  context.set('lastFlush', now);
  msg.csvRows = buffer;
  return msg;
}

return null;

const os = global.get('os') || require('os');
const path = global.get('path') || require('path');
const fs = global.get('fs') || require('fs');

// 出力ディレクトリ
const outputDir = path.join(os.homedir(), 'opcua_data');
if (!fs.existsSync(outputDir)) {
  fs.mkdirSync(outputDir, { recursive: true });
}

// 今日の日付でファイル名を決定
const today = new Date().toISOString().slice(0, 10); // YYYY-MM-DD
const filePath = path.join(outputDir, `opcua_${today}.csv`);

// ヘッダーが必要か確認
const needHeader = !fs.existsSync(filePath);

// CSVの行を生成
const rows = msg.csvRows;
let csvText = '';
if (needHeader) {
  csvText += 'timestamp,nodeId,value,dataType,status\n';
}

rows.forEach(row => {
  // 値にカンマ・改行が含まれる場合はダブルクォートで囲む
  const escapeCSV = (v) => {
    const s = String(v);
    return s.includes(',') || s.includes('\n') || s.includes('"')
      ? `"${s.replace(/"/g, '""')}"`
      : s;
  };
  csvText += [
    escapeCSV(row.ts),
    escapeCSV(row.nodeId),
    escapeCSV(row.value),
    escapeCSV(row.dataType),
    escapeCSV(row.status)
  ].join(',') + '\n';
});

try {
  fs.appendFileSync(filePath, csvText, 'utf8');
  node.log(`CSV書き込み完了: ${rows.length}件 → ${filePath}`);
  msg.payload = `✅ ${rows.length}件 → ${filePath}`;
} catch (e) {
  node.error('CSV書き込みエラー: ' + e.message);
  msg.payload = '❌ エラー: ' + e.message;
}

return msg;
